import{_ as t,o as a,c as o,ag as r}from"./chunks/framework.BBkp40gP.js";const g=JSON.parse('{"title":"Players","description":"","frontmatter":{},"headers":[],"relativePath":"for-players.md","filePath":"for-players.md"}'),i={name:"for-players.md"};function n(s,e,l,h,c,d){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="players" tabindex="-1">Players <a class="header-anchor" href="#players" aria-label="Permalink to &quot;Players&quot;">â€‹</a></h1><p>A quick orientation for anyone jumping into the mod.</p><h2 id="the-core-loop" tabindex="-1">The core loop <a class="header-anchor" href="#the-core-loop" aria-label="Permalink to &quot;The core loop&quot;">â€‹</a></h2><ol><li>Craft a <strong>Dirt Sapling</strong> from 8 dirt and an oak sapling.</li><li>Plant, wait for it to grow, break the logs with a <strong>Mallet</strong> to get a <strong>Stripped Logs</strong>.</li><li>Craft the stripped log into a <strong>Chunk</strong>, and combine 4 chunks + 4 apples + 1 honeycomb in a crafting table to produce the tree&#39;s output item.</li><li>Use unique methods of crafting, drying, and mutations to unlock new trees. More information on that below!</li></ol><h2 id="mallets" tabindex="-1">Mallets <a class="header-anchor" href="#mallets" aria-label="Permalink to &quot;Mallets&quot;">â€‹</a></h2><p>Break resource logs with a mallet to get stripped logs. Using a bare hand or an axe gives the base log the mallet is vanilla way to strip logs.</p><p>Mallet tiers affect durability cost. A netherite mallet on a dirt tree uses less durability than a wooden mallet on the same tree. Upgrading your mallet will be essential to keep the resources flowing.</p><h2 id="mutations" tabindex="-1">Mutations <a class="header-anchor" href="#mutations" aria-label="Permalink to &quot;Mutations&quot;">â€‹</a></h2><p>Some trees can only be obtained by mutating another tree into them. The process:</p><ol><li>Plant the required <strong>base sapling</strong> on dirt or grass.</li><li>Right-click the sapling with each required <strong>honeycomb</strong> in the recipe.</li><li>If the recipe has a <strong>catalyst</strong>, right-click with the catalyst item to consume it.</li><li>Place an <strong>Advanced Beehive</strong> nearby with bees inside.</li><li>Wait. Bees pollinate the sapling, and after the required number of cycles, it transforms into the mutated sapling.</li></ol><p>Mutation progress is shown in the <strong>Jade</strong> tooltip when looking at the sapling.</p><h2 id="drying-rack" tabindex="-1">Drying Rack <a class="header-anchor" href="#drying-rack" aria-label="Permalink to &quot;Drying Rack&quot;">â€‹</a></h2><p>Place a drying rack and right-click with a valid item to begin drying. After the drying time completes, the item transforms into its result.</p><h2 id="advanced-beehive" tabindex="-1">Advanced Beehive <a class="header-anchor" href="#advanced-beehive" aria-label="Permalink to &quot;Advanced Beehive&quot;">â€‹</a></h2><p>Holds up to 5 bees. When bees return from a resource sapling, they produce that tree&#39;s specific honeycomb. Use honeycombs in mutation recipes and resource crafts.</p>',15)])])}const u=t(i,[["render",n]]);export{g as __pageData,u as default};
